var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"지금은 바깥에 있는 저것들한테서 어떻게 벗어날지부터 고민해 봐야겠지만.","JPN":"とりあえず、外にいる奴らからどうやって逃げるか悩むべきだな。","ENG":"I guess we should worry about what to do with those guys out there first.","TWN":"現在要想的是怎麼擺脫外面那些傢伙。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"저것들...... 목적 없이 배회하는 게 아냐. 포위망을 좁히면서 뭔가를 찾고 있군.","JPN":"あいつら……目的もなく徘徊しているわけではない。包囲網を狭めながら何かを探している。","ENG":"Those C.O.s... They're not just wandering around aimlessly. They're encircling the area, deliberately looking for something.","TWN":"那些傢伙……不是無目的地亂晃。而是在慢慢縮小包圍圈，尋找什麼東西。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아마 저희일 거예요.","JPN":"おそらく私たちでしょう。","ENG":"They're probably looking for us.","TWN":"可能是我們吧。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"원래는 더 멀리 도망치려고 했는데 도중에 들켜서 여기 숨었거든요.","JPN":"本当はもっと遠くに逃げたかったんですけど、途中でバレてここに隠れたんです。","ENG":"We tried to run, but they spotted us, so we had to hide here.","TWN":"本來想逃到更遠的地方的，但是中途被發現了，所以躲到了這裡。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그래도 구조대가 소식이 없으면 다른 사람들이 찾으러 오지 않을까요?","JPN":"でも救助隊からの連絡がなかったら、他の人が探しに来てくれるかもしれないです！","ENG":"But don't you think people will come looking, since the rescue party can't be reached on comms?","TWN":"如果救援隊沒有消息的話，其他人會不會來找我們？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 때까지 여기 있기엔 시간이 없어. 그 전에 우리가 저 녀석들에게 발각될 거다.","JPN":"それまで持たない。その前に奴らに居場所がバレるだろう。","ENG":"We can't afford to stick around that long. Those things will find us before then.","TWN":"沒時間等到那時候了。因為在那之前，我們就會被這些傢伙發現。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......언니, 얘기할 때 술은 안 마셔도 되잖아요.","JPN":"……リタお姉ちゃん、こんな話の途中でまた飲むんですか？","ENG":"You don't really need to drink now, do you?","TWN":"……姐姐，說話的時候能不能不喝酒啊。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"물렁물렁하게 대하니까 또 잔소리 시작이군.","JPN":"ちょっと優しくされたからって調子に乗るんじゃない。","ENG":"There you go, nagging again because I've been soft on you.","TWN":"我稍微語氣好一點，你就又開始嘮叨了。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"헤헤......","JPN":"へへ……","ENG":"Heh heh...","TWN":"嘿嘿……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌, 뭐 뾰족한 수는 없나?","JPN":"ホライズン、何か手はないか？","ENG":"Got any good ideas, Horizon?","TWN":"地平線，你有什麼好辦法嗎？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"가능성을 걸어 볼 만한 곳은 있습니다.","JPN":"可能性をかけるに値する場所はあります。","ENG":"We may have better luck at a particular location I've found.","TWN":"有一個地方可以試一下。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"현 지점에서 남동쪽 방향으로 30여 킬로미터 떨어진 위치에서 유도 신호가 포착됩니다.","JPN":"現地点から南東方向に約30km離れた場所から誘導信号が探知されました。","ENG":"I'm detecting a signal about 30 clicks southeast from here.","TWN":"在此處東南方向30多公里的位置，捕捉到了引導信號。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"유도 신호요? 그게 뭔데요?","JPN":"誘導信号ですか？　それって？","ENG":"A signal? What is it?","TWN":"引導信號？那是什麼？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"함선이 이착륙할 때 유도해 주는 전파야.","JPN":"艦船が離着陸する時に誘導してくれる電波だ。","ENG":"It's a signal for guiding ships during take-off and landing.","TWN":"是艦船起降時的引導電波。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"관리국 직할 도시 선착장들은 그것 때문에 전화도 잘 안 터진다더군.","JPN":"管理局直轄の都市の船着場はそのせいで電話が繋がらない時も多いようだ。","ENG":"I hear those signals jam phone reception in the docks in the Administration Direct Control Cities.","TWN":"據說管理局直轄城市的碼頭因為這個電波，電話也打不通。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그건 낭설입니다. 전파 간섭 우려 때문에 사설 통신을 통제할 뿐이죠.","JPN":"それはデマです。電波干渉の恐れがあるため私設通信を統制するだけです。","ENG":"That's just an urban legend. They deliberately contain private communication out of concerns over jamming of the ships' signals.","TWN":"那是謠言。只是擔心干擾電波，所以控制私人通信而已。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"어쨌거나 포착된 신호는 강도가 미약한 데다, 현재 조약에 규정된 패턴도 아닙니다.","JPN":"いずれにせよ、捕捉された信号は強度が微弱であり、現在条約に規定されているパターンでもありません。","ENG":"In any case, the signal I'm detecting is faint at best. It isn't even a proper signal pattern.","TWN":"不管怎樣，捕捉到的信號強度微弱，而且也不是目前條約規定的模式。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};